#!/bin/bash
# AI HELPER — DEPLOY SCRIPT
# Extracts full source, installs deps, builds, and starts the app.
# Usage: bash DEPLOY.sh
set -euo pipefail

GREEN='\033[0;32m'; AMBER='\033[0;33m'; RED='\033[0;31m'; CYAN='\033[0;36m'; NC='\033[0m'
ok()   { echo -e "${GREEN}  ✓ $*${NC}"; }
warn() { echo -e "${AMBER}  ⚠ $*${NC}"; }
err()  { echo -e "${RED}  ✗ $*${NC}"; }
step() { echo -e "\n${CYAN}► $*${NC}"; }

APP_DIR="${HOME}/ai-helper-app"
AI_DIR="${HOME}/ai-helper"

echo ""
echo "╔══════════════════════════════════════════════════════════╗"
echo "║         AI HELPER — DEPLOY & BUILD                      ║"
echo "╚══════════════════════════════════════════════════════════╝"
echo ""

# ── Load nvm ────────────────────────────────────────────────
step "Loading Node.js environment..."
if   [ -s "${HOME}/.nvm/nvm.sh" ];        then export NVM_DIR="${HOME}/.nvm"
elif [ -s "${HOME}/.config/nvm/nvm.sh" ]; then export NVM_DIR="${HOME}/.config/nvm"
else
  _f=$(find "${HOME}" -name "nvm.sh" -maxdepth 5 2>/dev/null | head -1)
  [ -n "${_f}" ] && export NVM_DIR=$(dirname "${_f}") || { err "nvm not found — run INSTALL.sh first"; exit 1; }
fi
source "${NVM_DIR}/nvm.sh"
nvm use 20 2>/dev/null || nvm use default 2>/dev/null || true
node --version | grep -q "v2" || { err "Node 20 not found. Run: nvm install 20"; exit 1; }
ok "Node: $(node --version)"
which pnpm &>/dev/null || npm install -g pnpm -q
ok "pnpm: $(pnpm --version)"

# ── Extract embedded source archive ─────────────────────────
step "Extracting app source to ${APP_DIR}..."
mkdir -p "${APP_DIR}"

# Embedded tar.gz of app/ lib/ components/ config files
ARCHIVE_B64=''

echo "${ARCHIVE_B64}" | base64 -d | tar xz -C "${APP_DIR}"
ok "Source extracted"

# ── Write root config files ─────────────────────────────────
step "Writing config files..."

cat > "${APP_DIR}/package.json" << '__EOF__'
{
  "name": "vibe-next-template",
  "version": "0.1.0",
  "private": true,
  "scripts": {
    "dev": "next dev -p 13000",
    "build": "next build",
    "start": "next start -p 13000",
    "lint": "eslint --fix",
    "db:generate": "drizzle-kit generate",
    "db:migrate": "drizzle-kit migrate",
    "db:studio": "drizzle-kit studio",
    "build:worker": "opennextjs-cloudflare build",
    "preview": "opennextjs-cloudflare build && wrangler dev",
    "cf-typegen": "wrangler types --env-interface CloudflareEnv env.d.ts"
  },
  "dependencies": {
    "@hookform/resolvers": "^3.9.1",
    "@radix-ui/react-accordion": "1.2.12",
    "@radix-ui/react-alert-dialog": "1.1.15",
    "@radix-ui/react-aspect-ratio": "1.1.8",
    "@radix-ui/react-avatar": "1.1.11",
    "@radix-ui/react-checkbox": "1.3.3",
    "@radix-ui/react-collapsible": "1.1.12",
    "@radix-ui/react-context-menu": "2.2.16",
    "@radix-ui/react-dialog": "1.1.15",
    "@radix-ui/react-dropdown-menu": "2.1.16",
    "@radix-ui/react-hover-card": "1.1.15",
    "@radix-ui/react-label": "2.1.8",
    "@radix-ui/react-menubar": "1.1.16",
    "@radix-ui/react-navigation-menu": "1.2.14",
    "@radix-ui/react-popover": "1.1.15",
    "@radix-ui/react-progress": "1.1.8",
    "@radix-ui/react-radio-group": "1.3.8",
    "@radix-ui/react-scroll-area": "1.2.10",
    "@radix-ui/react-select": "2.2.6",
    "@radix-ui/react-separator": "1.1.8",
    "@radix-ui/react-slider": "1.3.6",
    "@radix-ui/react-slot": "1.2.4",
    "@radix-ui/react-switch": "1.2.6",
    "@radix-ui/react-tabs": "1.1.13",
    "@radix-ui/react-toast": "1.2.15",
    "@radix-ui/react-toggle": "1.1.10",
    "@radix-ui/react-toggle-group": "1.1.11",
    "@radix-ui/react-tooltip": "1.2.8",
    "@vercel/analytics": "1.6.1",
    "class-variance-authority": "^0.7.1",
    "clsx": "^2.1.1",
    "cmdk": "1.1.1",
    "date-fns": "4.1.0",
    "dotenv": "^17.3.1",
    "drizzle-orm": "^0.45.1",
    "embla-carousel-react": "8.6.0",
    "input-otp": "1.4.2",
    "lucide-react": "^0.564.0",
    "next": "^16.2.6",
    "next-themes": "^0.4.6",
    "postgres": "^3.4.8",
    "react": "19.2.4",
    "react-day-picker": "9.13.2",
    "react-dom": "19.2.4",
    "react-hook-form": "^7.54.1",
    "react-resizable-panels": "^2.1.7",
    "recharts": "2.15.0",
    "sonner": "^2.0.7",
    "tailwind-merge": "^3.5.0",
    "vaul": "^1.1.2",
    "zod": "^3.24.1",
    "zustand": "^5.0.11"
  },
  "devDependencies": {
    "@cloudflare/workers-types": "^4.20250109.0",
    "@opennextjs/cloudflare": "^1.19.10",
    "@tailwindcss/postcss": "^4.2.0",
    "@types/node": "^22",
    "@types/react": "19.2.14",
    "@types/react-dom": "19.2.3",
    "agentation": "^2.0.0",
    "drizzle-kit": "^0.31.9",
    "eslint": "^9",
    "eslint-config-next": "16.1.6",
    "postcss": "^8.5",
    "tailwindcss": "^4.2.0",
    "tw-animate-css": "1.3.3",
    "typescript": "5.7.3",
    "wrangler": "^4.86.0"
  }
}
__EOF__
ok "package.json written"

cat > "${APP_DIR}/tsconfig.json" << '__EOF__'
{
  "compilerOptions": {
    "target": "ES2017",
    "lib": [ "dom", "dom.iterable", "esnext" ],
    "allowJs": true,
    "skipLibCheck": true,
    "strict": true,
    "noEmit": true,
    "esModuleInterop": true,
    "module": "esnext",
    "moduleResolution": "bundler",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "jsx": "react-jsx",
    "incremental": true,
    "plugins": [
      {
        "name": "next"
      }
    ],
    "paths": {
      "@/*": [ "./*" ],
      "@bty/constant": [ "./package/constant" ],
      "@apis/oss": [ "./package/apis/oss" ],
      "@bty/uploader": [ "./package/uploader/src" ]
    }
  },
  "include": [
    "next-env.d.ts",
    "**/*.ts",
    "**/*.tsx",
    ".next/types/**/*.ts",
    ".next/dev/types/**/*.ts",
    "**/*.mts"
  ],
  "exclude": [ "node_modules", "llm-server" ]
}
__EOF__
ok "tsconfig.json written"

cat > "${APP_DIR}/postcss.config.mjs" << '__EOF__'
const config = {
  plugins: {
    '@tailwindcss/postcss': {},
  },
};

export default config;
__EOF__
ok "postcss.config.mjs written"

cat > "${APP_DIR}/next.config.ts" << '__EOF__'
import type { NextConfig } from 'next';
import dotenv from 'dotenv';

// Load .env into process.env (dotenv.populate is used internally to inject)
dotenv.config({ path: '.env', override: true });

const nextConfig: NextConfig = {
  reactStrictMode: false,
  turbopack: {},
  typescript: {
    ignoreBuildErrors: true,
  },
  env: {
    PROJECT_ID: process.env.HAPPYSEEDS_PROJECT_ID ?? '',
    REACTUS_BASE_URL: process.env.REACTUS_BASE_URL ?? '',
  },
  serverExternalPackages: [],
  allowedDevOrigins: [
    "**.*.*",
  ],
};

export default nextConfig;
__EOF__
ok "next.config.ts written"

# ── Install dependencies ────────────────────────────────────
step "Installing dependencies (takes 1-2 min)..."
cd "${APP_DIR}"
pnpm install 2>&1 | tail -5
ok "Dependencies installed"

# ── Create ~/ai-helper/ runtime dirs ────────────────────────
step "Creating runtime directories..."
mkdir -p "${AI_DIR}/scripts" "${AI_DIR}/logs" "${AI_DIR}/tmp" "${AI_DIR}/logs/archive"
ok "~/ai-helper/ structure created"

# ── Copy scripts ────────────────────────────────────────────
step "Installing automation scripts..."
for s in boot_dispatcher.sh maintenance_daily.sh watchdog_lite.sh shizuku_runner.sh; do
  if [ -f "${APP_DIR}/public/scripts/${s}" ]; then
    cp "${APP_DIR}/public/scripts/${s}" "${AI_DIR}/scripts/${s}"
    chmod +x "${AI_DIR}/scripts/${s}"
    ok "${s}"
  fi
done

# ── Write config.json ───────────────────────────────────────
if [ ! -f "${AI_DIR}/config.json" ]; then
  echo '{"destructive_mode":"B","watchdog_interval_minutes":15,"daily_maintenance_hour":3,"max_log_entries":100,"ai_helper_port":13000,"timeout_multiplier":1.0,"setup_complete":true}' > "${AI_DIR}/config.json"
  ok "config.json written"
fi

# ── Cron ────────────────────────────────────────────────────
step "Setting up cron jobs..."
EXISTING=$(crontab -l 2>/dev/null || echo "")
NEW="${EXISTING}"
echo "${EXISTING}" | grep -q "maintenance_daily" || NEW="${NEW}
0 3 * * * bash ${AI_DIR}/scripts/maintenance_daily.sh >> ${AI_DIR}/logs/maintenance.log 2>&1"
echo "${EXISTING}" | grep -q "watchdog_lite"     || NEW="${NEW}
*/15 * * * * bash ${AI_DIR}/scripts/watchdog_lite.sh >> ${AI_DIR}/logs/watchdog.log 2>&1"
printf "%b" "${NEW}" | crontab - 2>/dev/null && ok "Cron jobs installed" || warn "Could not write crontab — add manually"

# ── Build ───────────────────────────────────────────────────
step "Building app (takes ~30-60 seconds)..."
cd "${APP_DIR}"
pnpm build 2>&1 | tail -10
ok "Build complete"

echo ""
echo "╔══════════════════════════════════════════════════════════╗"
echo "║              DEPLOY COMPLETE!                           ║"
echo "╚══════════════════════════════════════════════════════════╝"
echo ""
echo "  Start the app:"
echo "    cd ~/ai-helper-app && pnpm start"
echo ""
echo "  Then open Chrome → http://localhost:13000"
echo ""
echo "  Or start now? (Ctrl+C to skip)"
sleep 3
cd "${APP_DIR}" && pnpm start
